#include<cstdio>
#include<algorithm>
#include<cstring>
using namespace std;
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
typedef long long LL; 
inline int read()
{
	int res(0);char ch(getchar());while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}

const int N=1e5+10,BK=512;int cnt[N],a[N],P[N],pp,n,Q,top,loc[N],blk,tmp[N],B[N/BK+100];LL Ans,ans[N];
struct Back{int p;LL a;inline Back(const int &P=0,const LL &A=0){p=P;a=A;}}stk[N];
struct Sort{int l,r,idx;inline bool operator<(const Sort &Q)const{return loc[l]==loc[Q.l]?r<Q.r:l<Q.l;}}t[N];
inline int fnd(const int &k){int l(1),r(pp),t(1),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1,t=m:r=m-1;return t;}
inline void ins(const int &x){Ans=max(Ans,1ll*P[x]*(++cnt[x]));stk[++top]=Back(x,Ans);}
inline void BackTo(const int &x){while(top>x){--cnt[stk[top].p];Ans=stk[top].a;--top;}}
inline void Init(){rep(1,n,i){loc[i]=(i-1)/BK+1;} blk=n/BK+1;rep(1,blk,i)B[i]=(i-1)*BK+1;}
inline LL BruteForce(const int &l,const int &r){LL res(0);rep(l,r,i)res=max(res,1ll*P[a[i]]*(++tmp[a[i]]));rep(l,r,i)tmp[a[i]]=0;return res;}
int main()
{
	n=read();Q=read();rep(1,n,i)P[i]=a[i]=read();Init();
	sort(P+1,P+n+1);pp=unique(P+1,P+n+1)-P-1;rep(1,n,i)a[i]=fnd(a[i]);
	rep(1,Q,i){t[i].l=read();t[i].r=read();t[i].idx=i;}sort(t+1,t+Q+1);
//	printf("B :: ");rep(1,blk,i)printf("%d ",B[i]);puts("");
//	rep(1,Q,i)printf("%d :: [%d,%d]\n",i,t[i].l,t[i].r);
	int cur=0,R=0,L=1;rep(1,Q,i)
	{
		if(loc[t[i].l]==loc[t[i].r]){ans[t[i].idx]=BruteForce(t[i].l,t[i].r);continue;}
		if(B[cur]<=t[i].l){while(B[cur]<=t[i].l)++cur;R=(L=B[cur])-1;memset(cnt,0,sizeof(cnt));top=Ans=0;}
		while(R<t[i].r)ins(a[++R]);int tmp=top;while(L>t[i].l)ins(a[--L]);//printf("%d :: (%d,%d) %lld\n",i,L,R,Ans);
		ans[t[i].idx]=Ans;BackTo(tmp); L=B[cur]; 
	}
	rep(1,Q,i)printf("%lld\n",ans[i]);return 0;	
}
